import{_ as e,o as l,c as t,ag as i}from"./chunks/framework.CAXxHpAX.js";const _=JSON.parse('{"title":"第 17 章 大规模机器学习","description":"","frontmatter":{},"headers":[],"relativePath":"ml/large-scale-ml.md","filePath":"ml/large-scale-ml.md","lastUpdated":1777303262000}'),p={name:"ml/large-scale-ml.md"};function o(r,a,s,n,d,c){return l(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-17-章-大规模机器学习" tabindex="-1">第 17 章 大规模机器学习 <a class="header-anchor" href="#第-17-章-大规模机器学习" aria-label="Permalink to &quot;第 17 章 大规模机器学习&quot;">​</a></h1><p>这一章讨论当训练集非常大时，如何更高效地训练模型。重点包括随机梯度下降、小批量梯度下降、在线学习和数据并行。</p><h2 id="_17-1-大型数据集的学习" tabindex="-1">17.1 大型数据集的学习 <a class="header-anchor" href="#_17-1-大型数据集的学习" aria-label="Permalink to &quot;17.1 大型数据集的学习&quot;">​</a></h2><p>大数据不一定总是有用。训练大规模模型前，应该先判断模型是否处于高方差状态。</p><p>如果模型高偏差，增加更多数据通常帮助有限。</p><p>如果模型高方差，增加数据可能显著改善泛化能力。</p><h2 id="_17-2-随机梯度下降法" tabindex="-1">17.2 随机梯度下降法 <a class="header-anchor" href="#_17-2-随机梯度下降法" aria-label="Permalink to &quot;17.2 随机梯度下降法&quot;">​</a></h2><p>批量梯度下降每次更新都要遍历所有训练样本。当 <code>m</code> 很大时，单次更新就很慢。</p><p>随机梯度下降每次只用一个训练样本更新参数。</p><p>流程：</p><ol><li>随机打乱训练集。</li><li>依次取一个样本。</li><li>用这个样本计算梯度并更新参数。</li><li>重复多轮。</li></ol><p>随机梯度下降不会像批量梯度下降那样平滑下降，而是在最小值附近波动。</p><h2 id="_17-3-小批量梯度下降" tabindex="-1">17.3 小批量梯度下降 <a class="header-anchor" href="#_17-3-小批量梯度下降" aria-label="Permalink to &quot;17.3 小批量梯度下降&quot;">​</a></h2><p>小批量梯度下降介于批量梯度下降和随机梯度下降之间。</p><p>每次使用 <code>b</code> 个样本更新参数。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>b = 10</span></span>
<span class="line"><span>b = 100</span></span></code></pre></div><p>小批量方法可以利用向量化计算，通常比单样本随机梯度下降更高效。</p><h2 id="_17-4-随机梯度下降收敛" tabindex="-1">17.4 随机梯度下降收敛 <a class="header-anchor" href="#_17-4-随机梯度下降收敛" aria-label="Permalink to &quot;17.4 随机梯度下降收敛&quot;">​</a></h2><p>监控随机梯度下降时，可以每隔一段时间计算最近若干样本的平均代价。</p><p>如果代价整体下降，说明学习率可能合适。</p><p>如果代价震荡很大或上升，可能需要减小学习率。</p><p>有时可以让学习率随迭代逐渐减小，使算法后期更稳定。</p><h2 id="_17-5-在线学习" tabindex="-1">17.5 在线学习 <a class="header-anchor" href="#_17-5-在线学习" aria-label="Permalink to &quot;17.5 在线学习&quot;">​</a></h2><p>在线学习适合数据流持续到来的场景。</p><p>例如网站不断有用户访问，每来一个样本，就用它更新一次模型，然后可以丢弃该样本。</p><p>在线学习适合：</p><ul><li>数据量很大。</li><li>数据分布随时间变化。</li><li>系统需要持续适应新用户行为。</li></ul><h2 id="_17-6-映射化简和数据并行" tabindex="-1">17.6 映射化简和数据并行 <a class="header-anchor" href="#_17-6-映射化简和数据并行" aria-label="Permalink to &quot;17.6 映射化简和数据并行&quot;">​</a></h2><p>当数据和计算量很大时，可以把任务分给多台机器或多个处理核心。</p><p>MapReduce 的思想：</p><ol><li>把数据分成多个子集。</li><li>每个机器计算一部分结果。</li><li>汇总所有机器的结果。</li></ol><p>很多机器学习算法中的求和运算都可以并行化，例如批量梯度下降中对所有样本的梯度求和。</p>`,32)])])}const u=e(p,[["render",o]]);export{_ as __pageData,u as default};
